    cat << 'EOF' > /home/user/wordlist.txt
password123
admin
qwerty
iloveyou
s3cr3t99
hunter2
spring2024
EOF

    cat << 'EOF' > /home/user/forensics/exfiltrated.json
[
  {"id": 1, "username": "admin", "email": "admin@local", "credit_card": "4111-2222-3333-4444"},
  {"id": 2, "username": "jsmith", "email": "jsmith@local", "credit_card": "5555-6666-7777-8888"}
]
EOF

    cd /home/user/forensics
    zip -P "s3cr3t99" payload.zip exfiltrated.json

    python3 -c "
import binascii
with open('payload.zip', 'rb') as f:
    data = f.read()
key = b'C2!x'
enc = bytearray(len(data))
for i in range(len(data)):
    enc[i] = data[i] ^ key[i % len(key)]
with open('payload.enc', 'w') as f:
    f.write(binascii.hexlify(enc).decode('ascii'))
"

    rm payload.zip exfiltrated.json
    cd /home/user

    chown -R user:user /home/user/forensics /home/user/wordlist.txt
    chmod -R 777 /home/user